import React from 'react';
import {
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Button,
  Stack,
  Chip,
  Box,
  Typography,
  Avatar,
  Card,
  CardContent,
  useTheme,
  alpha,
  Tooltip,
  IconButton,
} from '@mui/material';
import {
  AssignmentLate as AssignmentLateIcon,
  CheckCircle as ApproveIcon,
  Cancel as RejectIcon,
  Edit as EditIcon,
  Schedule as TimeIcon,
  Person as PersonIcon,
  Assignment as ProjectIcon,
  AccessTime as ClockIcon,
  CheckCircleOutline as StatusIcon,
  AttachMoney as MoneyIcon,
  RestartAlt as ResetIcon,
  Block as CancelIcon,
} from '@mui/icons-material';
import dayjs from 'dayjs';
import _ from 'lodash';
import { OT_STATUS } from 'utils/constants';

export default function OtCheckRe({
  timestamp,
  renderApprove,
  renderReject,
  renderCancel,
  renderEditButton,
  renderReset,
}) {
  const theme = useTheme();
  const hasData = timestamp?.rows && timestamp.rows.length > 0;

  const calculateHours = (startTime, endTime) => {
    return dayjs(endTime).diff(dayjs(startTime), 'hour', true).toFixed(1);
  };

  const getStatusColor = (status) => {
    return OT_STATUS?.[status]?.color || 'default';
  };

  const getStatusLabel = (status) => {
    return OT_STATUS?.[status]?.status_code || status;
  };

  const formatCurrency = (value) => {
    return new Intl.NumberFormat('th-TH', {
      style: 'currency',
      currency: 'THB',
    }).format(value || 0);
  };

  const getRateChip = (rate) => {
    const rateConfig = {
      1: { label: 'X1', color: 'primary' },
      1.5: { label: 'X1.5', color: 'warning' },
      3: { label: 'X3', color: 'error' },
    };
    const config = rateConfig[rate] || rateConfig[1];
    return (
      <Chip
        label={config.label}
        color={config.color}
        size="small"
        sx={{ fontWeight: 600 }}
      />
    );
  };

  if (!hasData) {
    return (
      <Card
        elevation={0}
        sx={{
          borderRadius: 3,
          border: '1px solid',
          borderColor: 'divider',
        }}
      >
        <CardContent sx={{ py: 8, textAlign: 'center' }}>
          <AssignmentLateIcon
            sx={{
              fontSize: 80,
              color: 'text.disabled',
              mb: 2,
              opacity: 0.5,
            }}
          />
          <Typography variant="h6" color="text.secondary" gutterBottom>
            ไม่มีรายการรออนุมัติ
          </Typography>
          <Typography variant="body2" color="text.secondary">
            ไม่พบข้อมูลการขอ OT ที่รออนุมัติในขณะนี้
          </Typography>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card
      elevation={0}
      sx={{
        borderRadius: 3,
        border: '1px solid',
        borderColor: 'divider',
      }}
    >
      <TableContainer>
        <Table>
          <TableHead>
            <TableRow
              sx={{
                bgcolor: theme.palette.primary.main,
                '& .MuiTableCell-root': {
                  color: 'white',
                  fontWeight: 600,
                  borderBottom: 'none',
                },
              }}
            >
              <TableCell align="center" sx={{ width: 60 }}>
                #
              </TableCell>
              <TableCell sx={{ minWidth: 140 }}>ผู้ทำรายการ</TableCell>
              <TableCell sx={{ minWidth: 180 }}>พนักงาน</TableCell>
              <TableCell sx={{ minWidth: 160 }}>โครงการ</TableCell>
              <TableCell align="center" sx={{ minWidth: 180 }}>
                วันที่และเวลา
              </TableCell>
              <TableCell align="center" sx={{ minWidth: 80 }}>
                อัตรา
              </TableCell>
              <TableCell sx={{ minWidth: 200 }}>รายละเอียด</TableCell>
              <TableCell align="center" sx={{ minWidth: 140 }}>
                สถานะ
              </TableCell>
              <TableCell align="center" sx={{ minWidth: 160 }}>
                จัดการ
              </TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {timestamp.rows.map((row, index) => {
              return (
                <TableRow
                  key={row._id || index}
                  sx={{
                    '&:hover': {
                      bgcolor: alpha(theme.palette.primary.main, 0.03),
                    },
                  }}
                >
                  {/* ลำดับ */}
                  <TableCell align="center">
                    <Typography variant="body2" fontWeight={600}>
                      {index + 1}
                    </Typography>
                  </TableCell>

                  {/* ผู้ทำรายการ */}
                  <TableCell>
                    <Stack direction="row" spacing={1} alignItems="center">
                      <Box>
                        <Typography variant="body2" fontWeight={500}>
                          {row?.resquester?.firstname}{' '}
                          {row?.resquester?.lastname}
                        </Typography>
                        <Typography variant="caption" color="text.secondary">
                          {row?.resquester?.department?.name || '-'}
                        </Typography>
                      </Box>
                    </Stack>
                  </TableCell>

                  {/* พนักงาน */}
                  <TableCell>
                    <Stack spacing={0.5}>
                      {_.map(row?.ot_lists, (e, idx) => (
                        <Box key={idx}>
                          <Typography variant="body2" fontWeight={500}>
                            {idx + 1}. {e?.employee_name}
                          </Typography>
                        </Box>
                      ))}
                    </Stack>
                  </TableCell>

                  {/* โครงการ */}
                  <TableCell>
                    <Stack direction="row" spacing={1} alignItems="center">
                      <ProjectIcon fontSize="small" color="action" />
                      <Box>
                        <Typography variant="body2" fontWeight={500}>
                          {row?.project?.project_number || 'N/A'}
                        </Typography>
                        <Typography variant="caption" color="text.secondary">
                          {row?.project?.name || 'ไม่ระบุโครงการ'}
                        </Typography>
                      </Box>
                    </Stack>
                  </TableCell>

                  {/* วันที่และเวลา */}
                  <TableCell align="center">
                    <Stack spacing={0.5} alignItems="center">
                      <Box
                        sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}
                      >
                        <Typography variant="body2" fontWeight={600}>
                          {dayjs(row?.date).format('DD/MM/YYYY')}
                        </Typography>
                      </Box>
                      <Box
                        sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}
                      >
                        <ClockIcon fontSize="small" color="action" />
                        <Typography variant="body2" fontWeight={500}>
                          {dayjs(row?.startTime).format('HH:mm')} -{' '}
                          {dayjs(row?.endTime).format('HH:mm')}
                        </Typography>
                      </Box>
                      <Chip
                        label={`${row?.total_hours.toFixed(1)} ชม.`}
                        size="small"
                        color="info"
                        variant="outlined"
                        sx={{ fontWeight: 600 }}
                      />
                    </Stack>
                  </TableCell>

                  {/* อัตรา */}
                  <TableCell align="center">{getRateChip(row?.rate)}</TableCell>

                  {/* รายละเอียด */}
                  <TableCell>
                    <Stack spacing={0.5}>
                      {row?.status_claim && (
                        <Chip
                          label="ขอโอทีย้อนหลัง"
                          size="small"
                          color="error"
                          variant="outlined"
                        />
                      )}
                      <Typography
                        variant="body2"
                        color="text.secondary"
                        sx={{
                          overflow: 'hidden',
                          textOverflow: 'ellipsis',
                          display: '-webkit-box',
                          WebkitLineClamp: 2,
                          WebkitBoxOrient: 'vertical',
                        }}
                      >
                        {row?.description || 'ไม่มีรายละเอียด'}
                      </Typography>
                    </Stack>
                  </TableCell>

                  {/* สถานะ */}
                  <TableCell align="center">
                    <Stack spacing={0.5} alignItems="center">
                      <Chip
                        label={getStatusLabel(row?.status)}
                        color={getStatusColor(row?.status)}
                        size="small"
                        sx={{ fontWeight: 600 }}
                      />
                      {row?.approver ? (
                        <Typography variant="caption" color="text.secondary">
                          โดย {row?.approver?.firstname}{' '}
                          {row?.approver?.lastname}
                        </Typography>
                      ) : (
                        <Typography variant="caption" color="text.secondary">
                          รออนุมัติ
                        </Typography>
                      )}
                    </Stack>
                  </TableCell>

                  {/* จัดการ */}
                  <TableCell align="center">
                    <Stack spacing={1}>
                      {row?.status === 'PENDING' ? (
                        <Stack spacing={1}>
                          <Button
                            variant="contained"
                            color="success"
                            size="small"
                            onClick={() => renderApprove(row)}
                            startIcon={<ApproveIcon />}
                            fullWidth
                          >
                            อนุมัติ
                          </Button>
                          <Button
                            variant="contained"
                            color="error"
                            size="small"
                            onClick={() => renderReject(row)}
                            startIcon={<RejectIcon />}
                            fullWidth
                          >
                            ปฏิเสธ
                          </Button>
                        </Stack>
                      ) : (
                        <div>
                          {row?.status !== 'CANCEL' && (
                            <Button
                              variant="contained"
                              color="warning"
                              size="small"
                              onClick={() => renderCancel(row)}
                              startIcon={<CancelIcon />}
                              fullWidth
                              sx={{ mb: 1 }}
                            >
                              ยกเลิก
                            </Button>
                          )}
                          {row?.status === 'CANCEL' && (
                            <Button
                              variant="contained"
                              color="info"
                              size="small"
                              onClick={() => renderReset(row)}
                              startIcon={<ResetIcon />}
                              fullWidth
                              sx={{ mb: 1 }}
                            >
                              Reset
                            </Button>
                          )}
                        </div>
                      )}
                      <Button
                        variant="outlined"
                        size="small"
                        startIcon={<EditIcon />}
                        onClick={() => renderEditButton(row)}
                        fullWidth
                      >
                        แก้ไข
                      </Button>
                    </Stack>
                  </TableCell>
                </TableRow>
              );
            })}
          </TableBody>
        </Table>
      </TableContainer>
    </Card>
  );
}
