import {
  Table,
  TableHead,
  TableContainer,
  Paper,
  TableCell,
  TableRow,
  TableBody,
  Button,
  TablePagination,
  Card,
  Avatar,
  Modal,
  Box,
  IconButton,
  Typography,
  Stack,
  Chip,
} from '@mui/material';
import PropTypes from 'prop-types';
import DeleteIcon from '@mui/icons-material/Delete';
import ModeEditIcon from '@mui/icons-material/ModeEdit';

import dayjs from 'dayjs';
import React from 'react';
import _ from 'lodash';
import { useHistory } from 'react-router';

const style = {
  position: 'absolute',
  top: '50%',
  left: '50%',
  transform: 'translate(-50%, -50%)',
  width: '100%',
  height: '80%',
  bgcolor: 'background.paper',
  boxShadow: 24,
  p: 4,
};

export default function HrcheckinListReportDailyByproject({
  timestamp,
  page,
  size,
  setPage,
  setSize,
  showSalary,
  handleEditTimestamp,
  handleEdit,
}) {
  const history = useHistory();
  const handleChangeRowsPerPage = (event) => {
    setSize(Number(event.target.value));
    setPage(1);
  };
  const handleChangePage = (event, newPage) => {
    setPage(newPage + 1);
  };

  const employees = timestamp?.employees || [];
  const personsCount = employees.length;

  const totalSalaryPerDay = _.sumBy(employees, (e) => e?.salary_per_day || 0);
  const totalAllowance = _.sumBy(employees, (e) => e?.allowance || 0);
  const totalAmount = _.sumBy(employees, (e) => e?.total || 0);

  const fmt = (v) =>
    Number(v || 0)
      .toFixed(2)
      .replace(/\d(?=(\d{3})+\.)/g, '$&,');

  const totalColumns = showSalary ? 14 : 11;

  // Helper to get OT hours by rate from otRequests
  const getOtHoursByRate = (otRequests, rate) => {
    if (!otRequests || otRequests.length === 0) return 0;
    return _.sumBy(
      otRequests.filter((ot) => ot.rate === rate),
      (ot) => ot.total_hours || 0,
    );
  };

  // Helper to get OT data by rate
  const getOtDataByRate = (otRequests, rate) => {
    if (!otRequests || otRequests.length === 0) return null;
    return otRequests.find((ot) => ot.rate === rate);
  };

  const sumOTcost = (otRequests) => {
    if (!otRequests || otRequests?.length === 0) return 0;
    return _.sumBy(otRequests, (ot) => ot?.total_price || 0);
  };

  return (
    <div className="py-2">
      <Paper>
        <TableContainer component={Paper}>
          <Table aria-label="report-table" size="small">
            <TableHead>
              <TableRow className={'bg-gray-600'}>
                <TableCell align="center">
                  <Typography className="text-white font-bold">No.</Typography>
                </TableCell>
                <TableCell>
                  <Typography className="text-white font-bold">Name</Typography>
                </TableCell>

                <TableCell align="center">
                  <Typography className="text-white font-bold">
                    Check in
                  </Typography>
                </TableCell>
                <TableCell align="center">
                  <Typography className="text-white font-bold">
                    Check out
                  </Typography>
                </TableCell>
                <TableCell align="center">
                  <Typography className="text-white font-bold">Rate</Typography>
                </TableCell>

                <TableCell align="center">
                  <Typography className="text-white font-bold">
                    OT X1
                  </Typography>
                </TableCell>
                <TableCell align="center">
                  <Typography className="text-white font-bold">
                    OT X1.5
                  </Typography>
                </TableCell>
                <TableCell align="center">
                  <Typography className="text-white font-bold">OTX3</Typography>
                </TableCell>

                {showSalary && (
                  <TableCell align="center">
                    <Typography className="text-white font-bold">
                      Labour cost
                    </Typography>
                  </TableCell>
                )}
                {showSalary && (
                  <TableCell align="center">
                    <Typography className="text-white font-bold">
                      Allowance
                    </Typography>
                  </TableCell>
                )}
                {showSalary && (
                  <TableCell align="center">
                    <Typography className="text-white font-bold">
                      OT cost
                    </Typography>
                  </TableCell>
                )}
                {showSalary && (
                  <TableCell align="center">
                    <Typography className="text-white font-bold">
                      Total
                    </Typography>
                  </TableCell>
                )}
                <TableCell align="center">
                  <Typography className="text-white font-bold">
                    Action
                  </Typography>
                </TableCell>
              </TableRow>
            </TableHead>

            <TableBody>
              {employees.length ? (
                <>
                  {employees.map((e, index) => {
                    const otX1 = getOtHoursByRate(e?.otRequests, 1);
                    const otX15 = getOtHoursByRate(e?.otRequests, 1.5);
                    const otX3 = getOtHoursByRate(e?.otRequests, 3);

                    const otX1Data = getOtDataByRate(e?.otRequests, 1);
                    const otX15Data = getOtDataByRate(e?.otRequests, 1.5);
                    const otX3Data = getOtDataByRate(e?.otRequests, 3);

                    return (
                      <TableRow key={e?._id || index}>
                        <TableCell align="center">{index + 1} </TableCell>
                        <TableCell>
                          {e?.name || '-'}{' '}
                          {e?.out_of_location ? (
                            <div>
                              <div>
                                <Chip
                                  label="Out of Location"
                                  color="error"
                                  size="small"
                                />
                              </div>
                              <p1>Note: {e?.note || '-'}</p1>
                            </div>
                          ) : (
                            ''
                          )}
                        </TableCell>
                        <TableCell align="center">
                          {e?.checkIn ? dayjs(e.checkIn).format('HH:mm') : '-'}
                        </TableCell>
                        <TableCell align="center">
                          {e?.checkOut
                            ? dayjs(e.checkOut).format('HH:mm')
                            : '-'}
                        </TableCell>
                        <TableCell align="center">{e?.rate ?? '-'}</TableCell>

                        <TableCell align="center">
                          {otX1 > 0 ? (
                            <Stack
                              direction="row"
                              spacing={0.5}
                              alignItems="center"
                              justifyContent="center"
                            >
                              <Typography variant="body2">
                                {otX1.toFixed(2)}
                              </Typography>
                              {otX1Data && handleEdit && (
                                <IconButton
                                  size="small"
                                  color="primary"
                                  onClick={() => handleEdit(otX1Data)}
                                >
                                  <ModeEditIcon fontSize="small" />
                                </IconButton>
                              )}
                            </Stack>
                          ) : (
                            '-'
                          )}
                        </TableCell>
                        <TableCell align="center">
                          {otX15 > 0 ? (
                            <Stack
                              direction="row"
                              spacing={0.5}
                              alignItems="center"
                              justifyContent="center"
                            >
                              <Typography variant="body2">
                                {otX15.toFixed(2)}
                              </Typography>
                              {otX15Data && handleEdit && (
                                <IconButton
                                  size="small"
                                  color="warning"
                                  onClick={() => handleEdit(otX15Data)}
                                >
                                  <ModeEditIcon fontSize="small" />
                                </IconButton>
                              )}
                            </Stack>
                          ) : (
                            '-'
                          )}
                        </TableCell>
                        <TableCell align="center">
                          {otX3 > 0 ? (
                            <Stack
                              direction="row"
                              spacing={0.5}
                              alignItems="center"
                              justifyContent="center"
                            >
                              <Typography variant="body2">
                                {otX3.toFixed(2)}
                              </Typography>
                              {otX3Data && handleEdit && (
                                <IconButton
                                  size="small"
                                  color="error"
                                  onClick={() => handleEdit(otX3Data)}
                                >
                                  <ModeEditIcon fontSize="small" />
                                </IconButton>
                              )}
                            </Stack>
                          ) : (
                            '-'
                          )}
                        </TableCell>

                        {showSalary && (
                          <TableCell align="right">
                            {typeof e?.salary_per_day === 'number'
                              ? fmt(e.salary_per_day)
                              : '-'}
                          </TableCell>
                        )}
                        {showSalary && (
                          <TableCell align="right">
                            {typeof e?.allowance === 'number'
                              ? fmt(e.allowance)
                              : '-'}
                          </TableCell>
                        )}
                        {showSalary && (
                          <TableCell align="right">
                            {sumOTcost(e?.otRequests).toFixed(2) || 0}
                          </TableCell>
                        )}
                        {showSalary && (
                          <TableCell align="right">
                            {typeof e?.total === 'number' ? fmt(e.total) : '-'}
                          </TableCell>
                        )}

                        <TableCell align="center">
                          <Button
                            variant="contained"
                            size="small"
                            startIcon={<ModeEditIcon />}
                            color="primary"
                            onClick={() => handleEditTimestamp(timestamp, e)}
                          >
                            Edit
                          </Button>
                        </TableCell>
                      </TableRow>
                    );
                  })}

                  <TableRow>
                    <TableCell colSpan={totalColumns} align="right">
                      <b>Total:</b> {personsCount}{' '}
                      <b>Person{personsCount !== 1 ? 's' : ''}</b>{' '}
                      {showSalary && (
                        <>
                          — Labour: {fmt(totalSalaryPerDay)} /day — Allowance:{' '}
                          {fmt(totalAllowance)} /day — Total: {fmt(totalAmount)}{' '}
                          /day
                        </>
                      )}
                    </TableCell>
                  </TableRow>
                </>
              ) : (
                <TableRow>
                  <TableCell align="center" colSpan={totalColumns}>
                    No items
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </TableContainer>
      </Paper>
    </div>
  );
}
